            @if (_loading)
            {
                <div class="text-center py-5">
                    <div class="spinner-border text-primary" role="status">
                        <span class="visually-hidden">Loading…</span>
                    </div>
                    <p class="mt-2 text-muted">Loading products…</p>
                </div>
            }
            else if (_result is null || _result.Items.Count == 0)
            {
                <div class="text-center py-5">
                    <p class="text-muted fs-5">No products found matching your criteria.</p>
                    <button class="btn btn-outline-primary" @onclick="ClearFiltersAsync">Clear Filters</button>
                </div>
            }
            else
            {
                <div class="row row-cols-1 row-cols-md-2 row-cols-lg-3 g-4">
                    @foreach (var product in _result.Items)
                    {
                        <div class="col">
                            <div class="card h-100 product-card" @onclick="() => OnProductSelected.InvokeAsync(product.Id)"
                                 style="cursor: pointer;" role="button" tabindex="0">
                                <div class="card-img-top bg-light d-flex align-items-center justify-content-center"
                                     style="height: 180px;" title="@product.Name">
                                    <span class="text-muted small">@product.Name</span>
                                </div>
                                <div class="card-body d-flex flex-column">
                                    <h6 class="card-title">@product.Name</h6>
                                    <p class="card-text fw-bold text-primary mb-1">@product.Price.ToString("C")</p>
                                    <p class="card-text mb-1">@GetStarRating(product.Rating)</p>
                                    @if (!product.InStock)
                                    {
                                        <span class="badge bg-danger mb-2" style="width: fit-content;">Out of Stock</span>
                                    }
                                    <div class="mt-auto">
                                        <button class="btn btn-sm btn-success w-100"
                                                disabled="@(!product.InStock)"
                                                @onclick="() => { }" @onclick:stopPropagation="true">
                                            Add to Cart
                                        </button>
                                    </div>
                                </div>
                            </div>
                        </div>
                    }
                </div>

                <!-- Pagination -->
                @if (TotalPages > 1)
                {
                    <nav class="mt-4" aria-label="Product pagination">
                        <ul class="pagination justify-content-center">
                            <li class="page-item @(_currentPage == 1 ? "disabled" : "")">
                                <button class="page-link" @onclick="() => GoToPageAsync(_currentPage - 1)"
                                        disabled="@(_currentPage == 1)">Previous</button>
                            </li>

                            @foreach (var page in GetPageNumbers())
                            {
                                <li class="page-item @(page == _currentPage ? "active" : "")">
                                    <button class="page-link" @onclick="() => GoToPageAsync(page)">@page</button>
                                </li>
                            }

                            <li class="page-item @(_currentPage == TotalPages ? "disabled" : "")">
                                <button class="page-link" @onclick="() => GoToPageAsync(_currentPage + 1)"
                                        disabled="@(_currentPage == TotalPages)">Next</button>
                            </li>
                        </ul>
                    </nav>
                }
            }
        </div>
    </div>
}

