+    {
+        if (isChecked)
+            _selectedCategories.Add(category);
+        else
+            _selectedCategories.Remove(category);
+    }
+
+    private async Task ApplyFiltersAsync()
+    {
+        _currentPage = 1;
+        await LoadDataAsync();
+    }
+
+    private async Task ClearFiltersAsync()
+    {
+        _selectedCategories.Clear();
+        _minPrice = null;
+        _maxPrice = null;
+        _inStockOnly = false;
+        _currentPage = 1;
+        _sortBy = "price_asc";
+        await LoadDataAsync();
+    }
+
+    private async Task OnSortChangedAsync(ChangeEventArgs e)
+    {
+        _sortBy = e.Value?.ToString() ?? "price_asc";
+        _currentPage = 1;
+        await LoadDataAsync();
+    }
+
+    private async Task GoToPageAsync(int page)
+    {
+        if (page < 1 || page > TotalPages) return;
+        _currentPage = page;
+        await LoadDataAsync();
+    }
+
+    private async Task RetryAsync()
+    {
+        await LoadDataAsync();
+    }
+
+    private static string GetStarRating(double rating)
+    {
+        var fullStars = (int)Math.Round(rating);
+        var emptyStars = 5 - fullStars;
+        return new string('★', fullStars) + new string('☆', emptyStars);
+    }
+
+    private IEnumerable<int> GetPageNumbers()
+    {
+        var total = TotalPages;
+        var current = _currentPage;
+        var start = Math.Max(1, current - 2);
+        var end = Math.Min(total, start + 4);
+        start = Math.Max(1, end - 4);
+
+        for (var i = start; i <= end; i++)
+            yield return i;
+    }
+}
